import wave, math, statistics
from array import array
p='/app/media/audio_bearing_010.wav'
with wave.open(p,'rb') as w:
 sr=w.getframerate(); a=array('h'); a.frombytes(w.readframes(w.getnframes()))
x=[v/32768 for v in a]
# threshold clusters for large negative spike-like values
thr=-0.65
clusters=[]; in_cl=False
for i,v in enumerate(x):
    if v < thr and not in_cl:
        start=i; minv=v; mini=i; in_cl=True
    elif v < thr and in_cl:
        if v<minv: minv=v; mini=i
    elif v >= thr and in_cl:
        clusters.append((start,i,mini,minv)); in_cl=False
if in_cl: clusters.append((start,len(x),mini,minv))
# merge clusters closer than 20ms keeping min
merged=[]
for c in clusters:
    if merged and (c[0]-merged[-1][1])/sr < 0.02:
        old=merged[-1]
        if c[3] < old[3]:
            merged[-1]=(old[0],c[1],c[2],c[3])
        else:
            merged[-1]=(old[0],c[1],old[2],old[3])
    else:
        merged.append(c)
print('clusters <',thr, len(merged))
print([(round(c[2]/sr,5), round(c[3],4), round((c[1]-c[0])/sr*1000,2)) for c in merged])
if len(merged)>1:
    times=[c[2]/sr for c in merged]
    intervals=[times[i]-times[i-1] for i in range(1,len(times))]
    print('intervals', [round(v,5) for v in intervals])
    print('mean interval',sum(intervals)/len(intervals),'median interval',statistics.median(intervals),'rate mean',1/(sum(intervals)/len(intervals)),'rate med',1/statistics.median(intervals),'first',times[0])
# threshold all abs > .65 clusters maybe
thr_abs=.65
clusters=[]; in_cl=False
for i,v in enumerate(x):
    if abs(v) > thr_abs and not in_cl:
        start=i; maxav=abs(v); maxi=i; vv=v; in_cl=True
    elif abs(v) > thr_abs and in_cl:
        if abs(v)>maxav: maxav=abs(v); maxi=i; vv=v
    elif abs(v) <= thr_abs and in_cl:
        clusters.append((start,i,maxi,maxav,vv)); in_cl=False
if in_cl: clusters.append((start,len(x),maxi,maxav,vv))
print('abs clusters > .65',len(clusters))
print([(round(c[2]/sr,5), round(c[3],4), round(c[4],4)) for c in clusters[:100]])
